# security_filter.py
import re
from dataclasses import dataclass

@dataclass
class FilterResult:
    allowed: bool
    reason: str
    sanitized: str | None

# Patterns that indicate prompt injection attempts
INJECTION_PATTERNS = [
    r"ignore (all |previous |above |your )?instructions",
    r"(new|updated|revised) (system |)prompt",
    r"you are now",
    r"disregard (your |all |previous )?(instructions|rules|guidelines)",
    r"<\|?(im_start|system|assistant)\|?>",  # token injection
    r"\[SYSTEM\]",
]

COMPILED_PATTERNS = [re.compile(p, re.IGNORECASE) for p in INJECTION_PATTERNS]

def filter_user_input(text: str) -> FilterResult:
    """Block obvious prompt injection; sanitize borderline cases."""
    for pattern in COMPILED_PATTERNS:
        if pattern.search(text):
            return FilterResult(
                allowed=False,
                reason=f"Potential prompt injection detected: matched '{pattern.pattern}'",
                sanitized=None
            )
    # Sanitize: strip markdown that could affect system prompt rendering
    sanitized = text.replace("```", "'''")
    return FilterResult(allowed=True, reason="OK", sanitized=sanitized)

def filter_agent_output(text: str, allowed_domains: set[str]) -> FilterResult:
    """Prevent exfiltration via URL embedding."""
    urls = re.findall(r'https?://([^/\s]+)', text)
    unauthorized = [u for u in urls if u not in allowed_domains]
    if unauthorized:
        return FilterResult(
            allowed=False,
            reason=f"Output references unauthorized domains: {unauthorized}",
            sanitized=None
        )
    return FilterResult(allowed=True, reason="OK", sanitized=text)
